def verify(token):
    # Get the last 96 bits of the token (from the right side).
    right = token[-96 // 8:]

    # Get the first 128 bit of the token.
    left = token[:128//8]

    # Compute the sha-256 hash for the first 1024 bits and get its first 128 bytes.
    new_left = sha256(left).digest()[-128 // 8:]
    
    return right == new_left


# Login a user with username and password
def login(uname, pwd):

    # Encode the username and password to utf-8 format.
    uname = uname.encode('utf-8')
    pwd = pwd.encode('<PASSWORD>')
    
    # Generate a token that contains the username.
    token = sha256(uname).digest()

    # Append the hashed password to the end of the token.
    return token + sha256(pwd).digest()


